// File: GcDemo.java
// Compile: javac GcDemo.java
// Run with GC log: java -Xmx200m -Xlog:gc* GcDemo
import java.util.*;

public class GcDemo {
  // Static list — anything we add here lives FOREVER
  static final List<byte[]> leakyCache = new ArrayList<>();

  public static void main(String[] args) throws Exception {
    // 1. See minor GCs happening normally
    System.out.println("phase 1: allocate and drop — objects die young, minor GC handles it");
    for (int i = 0; i < 200; i++) {
      byte[] b = new byte[1_000_000];      // 1 MB
      // b goes out of scope — GC will reclaim it soon
    }
    Thread.sleep(100);

    // 2. Cause a leak — put refs in a static that we never clear
    System.out.println("\nphase 2: LEAKY code — refs stored in static list");
    try {
      for (int i = 0; i < 500; i++) {
        leakyCache.add(new byte[1_000_000]);   // adds 1 MB to permanent hoard
      }
    } catch (OutOfMemoryError e) {
      System.out.println("OOM at " + leakyCache.size() + " MB in leakyCache");
      System.out.println("This is a MEMORY LEAK in a GC language — reachable but useless.");
    }

    // 3. Clean up (in real code — bounded cache with eviction!)
    leakyCache.clear();
    System.out.println("\nphase 3: after clearing static cache — next GC will reclaim");
    System.gc();
    Thread.sleep(200);

    System.out.println("free heap: " + Runtime.getRuntime().freeMemory() / (1024*1024) + " MB");
  }
}

// With -Xlog:gc* you'll see:
// [gc] Pause Young (Normal) (G1 Evacuation Pause) 20M->1M in 5ms   ← healthy minor GC
// ...
// [gc] Pause Young (Concurrent Start)   ← Old gen filling
// [gc] Pause Full (System.gc())   after phase 3
